import { Observable } from "rxjs";
import { debounceTime, distinctUntilChanged, filter, switchMap } from "rxjs";

interface SearchResult {
  id: string;
  title: string;
  score: number;
}

declare function searchApi$(q: string): Observable<SearchResult[]>;

export function typeahead(
  input$: Observable<string>
): Observable<SearchResult[]> {
  // switchMap cancels any in-flight request when a new keystroke arrives.
  // mergeMap here would race; concatMap would queue and feel laggy.
  return input$.pipe(
    debounceTime(300),
    distinctUntilChanged(),
    filter((q: string) => q.length >= 2),
    switchMap((q: string) => searchApi$(q))
  );
}
