import { Observable, Subject, merge } from "rxjs";
import { debounceTime, distinctUntilChanged, map, switchMap } from "rxjs";

interface FormState {
  title: string;
  body: string;
}

interface SaveResult {
  savedAt: number;
  ok: boolean;
}

declare function saveDraft$(state: FormState): Observable<SaveResult>;

export function autoSave(
  form$: Observable<FormState>,
  manualSave$: Subject<void>
): Observable<SaveResult> {
  const debounced$: Observable<FormState> = form$.pipe(
    debounceTime(800),
    distinctUntilChanged(
      (a: FormState, b: FormState) => a.title === b.title && a.body === b.body
    )
  );
  const forced$: Observable<FormState> = manualSave$.pipe(
    switchMap(() => form$.pipe(map((s) => s)))
  );
  // Merge debounced edits and explicit user saves; switchMap cancels an
  // in-flight save when a newer state arrives.
  return merge(debounced$, forced$).pipe(switchMap((state) => saveDraft$(state)));
}
