import { Observable, Subject } from "rxjs";

interface WireMessage {
  kind: "chat" | "presence";
  payload: string;
}

export interface SocketChannel {
  readonly incoming$: Observable<WireMessage>;
  readonly outgoing$: Subject<WireMessage>;
  close(): void;
}

declare class WebSocket {
  constructor(url: string);
  onmessage: ((ev: { data: string }) => void) | null;
  onerror: ((ev: unknown) => void) | null;
  onclose: (() => void) | null;
  send(data: string): void;
  close(): void;
}

export function createSocket(url: string): SocketChannel {
  const outgoing$ = new Subject<WireMessage>();
  const ws = new WebSocket(url);

  const incoming$ = new Observable<WireMessage>((sub) => {
    ws.onmessage = (ev) => sub.next(JSON.parse(ev.data) as WireMessage);
    ws.onerror = (e) => sub.error(e);
    ws.onclose = () => sub.complete();
    const sendSub = outgoing$.subscribe((m) => ws.send(JSON.stringify(m)));
    return () => {
      sendSub.unsubscribe();
      ws.close();
    };
  });

  return { incoming$, outgoing$, close: () => ws.close() };
}
