import { Observable, ReplaySubject } from "rxjs";
import { tap } from "rxjs";

interface ChatMsg {
  id: string;
  user: string;
  text: string;
  ts: number;
}

declare class WebSocket {
  constructor(url: string);
  onmessage: ((ev: { data: string }) => void) | null;
  onclose: (() => void) | null;
  close(): void;
}

export function chatStream(url: string): Observable<ChatMsg> {
  // ReplaySubject buffers the last 20 messages so late subscribers
  // (e.g. a re-mounted chat panel) see recent history immediately.
  const history$ = new ReplaySubject<ChatMsg>(20);

  const ws = new WebSocket(url);
  const raw$ = new Observable<ChatMsg>((sub) => {
    ws.onmessage = (ev) => sub.next(JSON.parse(ev.data) as ChatMsg);
    ws.onclose = () => sub.complete();
    return () => ws.close();
  });

  raw$.pipe(tap((m) => history$.next(m))).subscribe();
  return history$.asObservable();
}
```

Construct an `Observable<T>` whose teardown closes the socket. The subscriber callback wires `onmessage` to `next` and `onclose` to `complete`, and returns a teardown function that closes the socket when the consumer unsubscribes.

```typescript
import { Observable } from "rxjs";

interface Msg {
  topic: string;
  data: string;
}

declare class WebSocket {
  constructor(url: string);
  onmessage: ((ev: { data: string }) => void) | null;
  onclose: (() => void) | null;
  onerror: ((ev: unknown) => void) | null;
  close(): void;
}

export function fromSocket(url: string): Observable<Msg> {
  return new Observable<Msg>((sub) => {
    const ws = new WebSocket(url);
    ws.onmessage = (ev) => sub.next(JSON.parse(ev.data) as Msg);
    ws.onerror = (e) => sub.error(e);
    ws.onclose = () => sub.complete();
    return () => ws.close();
  });
}
```

Model the socket as two streams: an inbound `Observable<T>` built from `new Observable` that wires `onmessage` to `next` and closes on `onclose`, and an outbound `Subject<T>` whose subscription forwards each emission to `ws.send`. Wrap the inbound stream in `retry({ count, delay })` so a dropped connection reconnects with a backoff. Teardown must close the socket to prevent leaks.

```typescript
import { Observable, Subject, timer } from "rxjs";
import { retry } from "rxjs";

interface Frame {
  kind: string;
  body: string;
}

declare class WebSocket {
  constructor(url: string);
  onopen: (() => void) | null;
  onmessage: ((ev: { data: string }) => void) | null;
  onclose: (() => void) | null;
  onerror: ((ev: unknown) => void) | null;
  send(data: string): void;
  close(): void;
}

export interface Channel {
  incoming$: Observable<Frame>;
  outgoing$: Subject<Frame>;
}

export function connect(url: string): Channel {
  const outgoing$ = new Subject<Frame>();
  const incoming$ = new Observable<Frame>((sub) => {
    const ws = new WebSocket(url);
    ws.onmessage = (ev) => sub.next(JSON.parse(ev.data) as Frame);
    ws.onerror = (e) => sub.error(e);
    ws.onclose = () => sub.complete();
    const outSub = outgoing$.subscribe((f) => ws.send(JSON.stringify(f)));
    return () => {
      outSub.unsubscribe();
      ws.close();
    };
  }).pipe(
    retry({ count: 5, delay: (_err, n) => timer(Math.min(2 ** n * 250, 10_000)) })
  );

  return { incoming$, outgoing$ };
}
```

