import { Observable, ReplaySubject } from "rxjs";
import { shareReplay, tap } from "rxjs";

interface Tick {
  symbol: string;
  priceCents: number;
  ts: number;
}

declare class WebSocket {
  constructor(url: string);
  onmessage: ((ev: { data: string }) => void) | null;
  onclose: (() => void) | null;
  close(): void;
}

export function tickerStream(url: string): Observable<Tick> {
  const lastTick$ = new ReplaySubject<Tick>(1);

  const raw$ = new Observable<Tick>((sub) => {
    const ws = new WebSocket(url);
    ws.onmessage = (ev) => sub.next(JSON.parse(ev.data) as Tick);
    ws.onclose = () => sub.complete();
    return () => ws.close();
  });

  // shareReplay({ bufferSize: 1, refCount: true }) multicasts one socket to
  // many subscribers and tears the upstream down when the last leaves.
  return raw$.pipe(
    tap((t) => lastTick$.next(t)),
    shareReplay({ bufferSize: 1, refCount: true })
  );
}
```

Fix this v6-style socket wrapper to use v7 `retry({ delay })` instead of `retryWhen`.

```typescript
