import { Observable } from "rxjs";
import { map, scan } from "rxjs";

interface ByteEvent {
  loaded: number;
  total: number;
}

interface Progress {
  loaded: number;
  total: number;
  percent: number;
}

export function uploadProgress(
  bytes$: Observable<ByteEvent>
): Observable<Progress> {
  // scan accumulates the running max loaded so out-of-order events don't
  // cause the bar to jump backwards.
  return bytes$.pipe(
    scan<ByteEvent, Progress>(
      (acc, e) => ({
        loaded: Math.max(acc.loaded, e.loaded),
        total: e.total,
        percent: e.total > 0 ? Math.round((e.loaded / e.total) * 100) : 0,
      }),
      { loaded: 0, total: 0, percent: 0 }
    ),
    map((p: Progress) => p)
  );
}
