```typescript
import { Observable, Subject } from "rxjs";
import { scan } from "rxjs";

type UploadEvent =
  | { kind: "progress"; loaded: number; total: number }
  | { kind: "done"; url: string }
  | { kind: "error"; message: string };

interface UploadState {
  percent: number;
  done: boolean;
  url: string | null;
  error: string | null;
}

export function uploadState(events$: Observable<UploadEvent>): Observable<UploadState> {
  const initial: UploadState = { percent: 0, done: false, url: null, error: null };
  return events$.pipe(
    scan<UploadEvent, UploadState>((s, ev) => {
      if (ev.kind === "progress") {
        const percent = ev.total > 0 ? Math.round((ev.loaded / ev.total) * 100) : 0;
        return { ...s, percent };
      }
      if (ev.kind === "done") return { ...s, percent: 100, done: true, url: ev.url };
      return { ...s, error: ev.message };
    }, initial)
  );
}

export const upload$ = new Subject<UploadEvent>();
```

Use `scan` to fold the raw byte events into a running `{ loaded, total, percent }` view model. `scan` is the right shape because each emission depends on the previous one — `map` is stateless and would have to read from a closure variable.

```typescript
