import { scan } from "rxjs";

interface ProgressEvent {
  loaded: number;
  total: number;
}

export function toPercent(
  bytes$: Observable<ProgressEvent>
): Observable<number> {
  return bytes$.pipe(
    scan<ProgressEvent, number>(
      (_prev, e) => (e.total > 0 ? Math.round((e.loaded / e.total) * 100) : 0),
      0
