Represent every file's progress event as a discriminated wire type, use `scan` to fold emissions into a `Map<fileId, Progress>`, and derive an aggregate `percent` from the total loaded vs total size. `scan` is stateful and emits on every update, which matches what a progress UI wants — no need to manage the map in a ref outside the pipeline.

```typescript
import { Observable } from "rxjs";
import { scan } from "rxjs";

interface FileProgress {
  fileId: string;
  loaded: number;
  total: number;
}

interface Aggregate {
  perFile: Map<string, FileProgress>;
  totalLoaded: number;
  totalSize: number;
  percent: number;
}

export function multiFileProgress(
  events$: Observable<FileProgress>
): Observable<Aggregate> {
  const initial: Aggregate = {
    perFile: new Map(),
    totalLoaded: 0,
    totalSize: 0,
    percent: 0,
  };
  return events$.pipe(
    scan<FileProgress, Aggregate>((acc, ev) => {
      const perFile = new Map(acc.perFile);
      perFile.set(ev.fileId, ev);
      let loaded = 0;
      let size = 0;
      perFile.forEach((p) => {
        loaded += p.loaded;
        size += p.total;
      });
      return {
        perFile,
        totalLoaded: loaded,
        totalSize: size,
        percent: size > 0 ? Math.round((loaded / size) * 100) : 0,
      };
    }, initial)
  );
}
```

