import { Observable } from "rxjs";
import { scan } from "rxjs";

type UploadEvent =
  | { kind: "progress"; loaded: number; total: number }
  | { kind: "complete"; url: string };

interface UploadView {
  percent: number;
  finished: boolean;
  url: string | null;
}

export function uploadView(
  source$: Observable<UploadEvent>
): Observable<UploadView> {
  const initial: UploadView = { percent: 0, finished: false, url: null };
  return source$.pipe(
    scan<UploadEvent, UploadView>((s, ev) => {
      switch (ev.kind) {
        case "progress":
          return {
            ...s,
            percent: ev.total > 0 ? Math.round((ev.loaded / ev.total) * 100) : 0,
          };
        case "complete":
          return { percent: 100, finished: true, url: ev.url };
      }
    }, initial)
  );
