Pipe the field value through `debounceTime` + `distinctUntilChanged`, then use `switchMap` to call the async validator. `switchMap` unsubscribes from any pending check the moment a new value arrives, so a slow check can never overwrite a newer value's result.

```typescript
import { Observable, of } from "rxjs";
import { debounceTime, distinctUntilChanged, switchMap } from "rxjs";

declare function isAvailable$(value: string): Observable<boolean>;

export function liveValidate(
  value$: Observable<string>
): Observable<"ok" | "taken" | "empty"> {
  return value$.pipe(
    debounceTime(300),
    distinctUntilChanged(),
    switchMap((v) =>
      v.length === 0
        ? of<"empty">("empty")
        : isAvailable$(v).pipe(
            // map to the literal union
            switchMap((ok) => of<"ok" | "taken">(ok ? "ok" : "taken"))
          )
    )
  );
}
```

Submit-time validation runs once at a discrete moment — you just call the validator and surface the result. Live validation runs continuously as the user types, so it needs two safety nets: `debounceTime` to avoid hammering the server on every keystroke, and `switchMap` to cancel any in-flight check when the value changes. Without `switchMap` a slow earlier check can resolve after a newer one and display the wrong verdict.

```typescript
import { Observable, of } from "rxjs";
import { catchError, debounceTime, distinctUntilChanged, map, switchMap } from "rxjs";

type SlugStatus =
  | { kind: "checking" }
  | { kind: "ok" }
  | { kind: "taken" }
  | { kind: "invalid"; reason: string };

declare function slugAvailable$(slug: string): Observable<boolean>;

export function validateSlug(
  value$: Observable<string>
): Observable<SlugStatus> {
  return value$.pipe(
    debounceTime(250),
    distinctUntilChanged(),
    switchMap<string, Observable<SlugStatus>>((v) => {
      if (!/^[a-z0-9-]+$/.test(v)) {
        return of<SlugStatus>({ kind: "invalid", reason: "lowercase alphanumeric only" });
      }
      return slugAvailable$(v).pipe(
        map<boolean, SlugStatus>((ok) => (ok ? { kind: "ok" } : { kind: "taken" })),
        catchError((e: unknown) =>
          of<SlugStatus>({ kind: "invalid", reason: String(e) })
        )
      );
    })
  );
}
