  password$: Observable<string>
): Observable<LoginVM> {
  return combineLatest({ email: email$, password: password$ }).pipe(
    map(
      ({ email, password }): LoginVM => ({
        email,
        password,
        canSubmit: email.includes("@") && password.length >= 8,
      })
    )
  );
}
