import { BehaviorSubject, Observable, combineLatest } from "rxjs";
import { map } from "rxjs";

interface ProfileVM {
  displayName: string;
  bio: string;
  avatarUrl: string;
  dirty: boolean;
  valid: boolean;
}

interface Initial {
  displayName: string;
  bio: string;
  avatarUrl: string;
}

export function profileForm(initial: Initial): {
  displayName$: BehaviorSubject<string>;
  bio$: BehaviorSubject<string>;
  avatarUrl$: BehaviorSubject<string>;
  state$: Observable<ProfileVM>;
} {
  const displayName$ = new BehaviorSubject<string>(initial.displayName);
  const bio$ = new BehaviorSubject<string>(initial.bio);
  const avatarUrl$ = new BehaviorSubject<string>(initial.avatarUrl);

  const state$: Observable<ProfileVM> = combineLatest({
    displayName: displayName$,
    bio: bio$,
    avatarUrl: avatarUrl$,
  }).pipe(
    map(({ displayName, bio, avatarUrl }): ProfileVM => ({
      displayName,
      bio,
      avatarUrl,
      dirty:
        displayName !== initial.displayName ||
        bio !== initial.bio ||
        avatarUrl !== initial.avatarUrl,
      valid: displayName.trim().length > 0,
    }))
  );

  return { displayName$, bio$, avatarUrl$, state$ };
}
